-- ============================================================
-- VÍNCULOS DE CASAL (após inserção, vincular parceiros)
-- Identificados no XLS: Cintia + Thiago Grigoletto, Lorhana + Adelmo (responsável)
-- ============================================================

-- Vincular Cintia Grigoletto <-> Thiago Grigoletto
UPDATE patients p1
SET parceiro_id = (SELECT id FROM patients WHERE nome = 'Thiago Grigoletto' LIMIT 1)
WHERE p1.nome = 'Cintia Grigoletto';

UPDATE patients p1
SET parceiro_id = (SELECT id FROM patients WHERE nome = 'Cintia Grigoletto' LIMIT 1)
WHERE p1.nome = 'Thiago Grigoletto';
